template <typename T, int COMPUTE_ITERATIONS, int ELEMENTS_PER_THREAD,
          int FUSION_DEGREE, bool BLOCK_STRIDED>
__global__ void benchmark_kernel(T seed, T* g_data) {
  const unsigned int blockSize = blockDim.x;
  int stride;
  int idx;
  if (BLOCK_STRIDED) {
    stride = blockSize;
    idx = (int)blockIdx.x * (int)blockSize * ELEMENTS_PER_THREAD + (int)threadIdx.x;
  } else {
    const int grid_size = (int)blockSize * (int)gridDim.x;
    stride = grid_size;
    idx = (int)(blockIdx.x * blockDim.x + threadIdx.x);
  }
  const int big_stride = (int)gridDim.x * (int)blockSize * ELEMENTS_PER_THREAD;

  T tmps[ELEMENTS_PER_THREAD];
  #pragma unroll
  for (int k = 0; k < FUSION_DEGREE; k++) {
    #pragma unroll
    for (int j = 0; j < ELEMENTS_PER_THREAD; j++) {
      tmps[j] = g_data[idx + j * stride + k * big_stride];
      #pragma unroll
      for (int i = 0; i < COMPUTE_ITERATIONS; i++) {
        tmps[j] = t_add(t_mul(tmps[j], tmps[j]), seed);
      }
    }

    T sum = t_zero<T>();
    #pragma unroll
    for (int j = 0; j < ELEMENTS_PER_THREAD; j += 2) {
      sum = t_add(sum, t_mul(tmps[j], tmps[j + 1]));
    }

    if (t_equal(sum, t_neg_one<T>())) {
      g_data[idx + k * big_stride] = sum;
    }
  }
}

__global__ void warmup_kernel(short seed, short* g_data, long n) {
  long idx = (long)blockIdx.x * blockDim.x + threadIdx.x;
  if (idx < n) {
    short v = g_data[idx];
    g_data[idx] = (short)(v + seed - seed);
  }
}

template <typename LaunchFn>
static double measure_kernel_time_ms(LaunchFn&& fn) {
  constexpr int total_bench_iterations = 3;
  double acc = 0.0;
  for (int i = 0; i < total_bench_iterations; i++) {
    cudaEvent_t ev_start, ev_stop;
    CUDA_SAFE_CALL(cudaEventCreate(&ev_start));
    CUDA_SAFE_CALL(cudaEventCreate(&ev_stop));
    CUDA_SAFE_CALL(cudaEventRecord(ev_start, 0));
    fn();
    CUDA_SAFE_CALL(cudaEventRecord(ev_stop, 0));
    CUDA_SAFE_CALL(cudaEventSynchronize(ev_stop));
    float ms = 0.0f;
    CUDA_SAFE_CALL(cudaEventElapsedTime(&ms, ev_start, ev_stop));
    CUDA_SAFE_CALL(cudaEventDestroy(ev_start));
    CUDA_SAFE_CALL(cudaEventDestroy(ev_stop));
    acc += (double)ms;
  }
  return acc / total_bench_iterations;
}

template <typename T, int ELEMENTS_PER_THREAD, int FUSION_DEGREE, bool BLOCK_STRIDED>
static void launch_by_compute_iters(int iters, T seed, T* cbuffer, dim3 grid, dim3 block) {
#define LAUNCH_CASE(N) \
  case N: benchmark_kernel<T, N, ELEMENTS_PER_THREAD, FUSION_DEGREE, BLOCK_STRIDED><<<grid, block>>>(seed, cbuffer); break
  switch (iters) {
    LAUNCH_CASE(0); LAUNCH_CASE(1); LAUNCH_CASE(2); LAUNCH_CASE(3); LAUNCH_CASE(4);
    LAUNCH_CASE(5); LAUNCH_CASE(6); LAUNCH_CASE(7); LAUNCH_CASE(8); LAUNCH_CASE(9);
    LAUNCH_CASE(10); LAUNCH_CASE(11); LAUNCH_CASE(12); LAUNCH_CASE(13); LAUNCH_CASE(14);
    LAUNCH_CASE(15); LAUNCH_CASE(16); LAUNCH_CASE(17); LAUNCH_CASE(18); LAUNCH_CASE(20);
    LAUNCH_CASE(22); LAUNCH_CASE(24); LAUNCH_CASE(28); LAUNCH_CASE(32); LAUNCH_CASE(40);
    LAUNCH_CASE(48); LAUNCH_CASE(56); LAUNCH_CASE(64); LAUNCH_CASE(80); LAUNCH_CASE(96);
    LAUNCH_CASE(128); LAUNCH_CASE(192); LAUNCH_CASE(256);
    default: break;
  }
#undef LAUNCH_CASE
}

extern "C" void mixbenchGPU(double* c, long size) {
  const bool block_strided = false;
  const bool host_allocated = false;
  const bool use_os_timer = false;
  const size_t workgroupsize = 256;
  const unsigned int elements_per_wi = 8;
  const unsigned int fusion_degree = 4;

  const char* benchtype = block_strided ? "Workgroup" : "NDRange";
  printf("Workitem stride:        %s\n", benchtype);
  const char* buffer_allocation = host_allocated ? "Host allocated" : "Device allocated";
  printf("Buffer allocation:      %s\n", buffer_allocation);
  printf("Timer:                  %s\n", use_os_timer ? "OS based" : "CL event based");

  cudaDeviceProp prop = GetDeviceProperties();
  bool enable_dp = (prop.major > 1) || (prop.major == 1 && prop.minor >= 3);
  if (!enable_dp) {
    printf("Warning:                Double precision computations are not supported\n");
  }
  bool enable_hp = IsFP16Supported();
  if (!enable_hp) {
    printf("Warning:                Half precision computations are not supported\n");
  }

  double* d_buffer = nullptr;
  CUDA_SAFE_CALL(cudaMalloc((void**)&d_buffer, size * sizeof(double)));
  CUDA_SAFE_CALL(cudaMemset(d_buffer, 0, size * sizeof(double)));

  printf("Loading kernel source file...\n");
  printf("Precompilation of kernels... ");
  show_progress_init(compute_iterations_len);
  for (int i = 0; i < compute_iterations_len; i++) {
    show_progress_step(0, '\\');
    show_progress_step(0, '|');
    if (enable_dp) show_progress_step(0, '/');
    if (enable_hp) show_progress_step(0, '-');
    show_progress_step(1, '>');
  }
  show_progress_done();

  {
    const long reduced_grid_size = size / 256;
    dim3 block((unsigned int)workgroupsize);
    dim3 grid((unsigned int)((reduced_grid_size + (long)workgroupsize - 1) / (long)workgroupsize));
    warmup_kernel<<<grid, block>>>(1, (short*)d_buffer, reduced_grid_size);
    CUDA_SAFE_CALL(cudaGetLastError());
    CUDA_SAFE_CALL(cudaDeviceSynchronize());
  }

  printf("-------------------------------------------------------------------------------------------------------------- CSV data --------------------------------------------------------------------------------------------------------------\n");
  printf("Experiment ID, Single Precision ops,,,,              Double precision ops,,,,              Half precision ops,,,,                Integer operations,,, \n");
  printf("Compute iters, Flops/byte, ex.time,  GFLOPS, GB/sec, Flops/byte, ex.time,  GFLOPS, GB/sec, Flops/byte, ex.time,  GFLOPS, GB/sec, Iops/byte, ex.time,   GIOPS, GB/sec\n");

  const long compute_grid_size = size / (long)elements_per_wi / (long)fusion_degree;
  dim3 block((unsigned int)workgroupsize);
  dim3 grid((unsigned int)(compute_grid_size / (long)workgroupsize));

  for (int krn_idx = 0; krn_idx < compute_iterations_len; krn_idx++) {
    const int current_compute_iterations = compute_iterations[krn_idx];
    const long long computations =
        (elements_per_wi * (long long)compute_grid_size +
         (2 * elements_per_wi * current_compute_iterations) * (long long)compute_grid_size) *
        fusion_degree;
    const long long memoryoperations = size;

    double kernel_time_mad_sp = measure_kernel_time_ms([&]() {
      const float seed_f = 1.0f;
      launch_by_compute_iters<float, 8, 4, false>(current_compute_iterations, seed_f, (float*)d_buffer, grid, block);
      CUDA_SAFE_CALL(cudaGetLastError());
    });

    double kernel_time_mad_dp = 0.0;
    if (enable_dp) {
      kernel_time_mad_dp = measure_kernel_time_ms([&]() {
        const double seed_d = 1.0;
        launch_by_compute_iters<double, 8, 4, false>(current_compute_iterations, seed_d, (double*)d_buffer, grid, block);
        CUDA_SAFE_CALL(cudaGetLastError());
      });
    }

    double kernel_time_mad_hp = 0.0;
    if (enable_hp) {
      kernel_time_mad_hp = measure_kernel_time_ms([&]() {
        const __half2 seed_h = __float2half2_rn(1.0f);
        launch_by_compute_iters<__half2, 8, 4, false>(current_compute_iterations, seed_h, (__half2*)d_buffer, grid, block);
        CUDA_SAFE_CALL(cudaGetLastError());
      });
    }

    double kernel_time_mad_int = measure_kernel_time_ms([&]() {
      const int seed_i = 1;
      launch_by_compute_iters<int, 8, 4, false>(current_compute_iterations, seed_i, (int*)d_buffer, grid, block);
      CUDA_SAFE_CALL(cudaGetLastError());
    });

    printf(
        "         %4d,   %8.3f,%8.2f,%8.2f,%7.2f,   %8.3f,%8.2f,%8.2f,%7.2f,   "
        "%8.3f,%8.2f,%8.2f,%7.2f,  %8.3f,%8.2f,%8.2f,%7.2f\n",
        current_compute_iterations,
        ((double)computations) / ((double)memoryoperations * sizeof(float)),
        kernel_time_mad_sp,
        ((double)computations) / kernel_time_mad_sp * 1000. / (double)(1000 * 1000 * 1000),
        ((double)memoryoperations * sizeof(float)) / kernel_time_mad_sp * 1000. / (1000. * 1000. * 1000.),
        ((double)computations) / ((double)memoryoperations * sizeof(double)),
        kernel_time_mad_dp,
        kernel_time_mad_dp > 0.0 ? ((double)computations) / kernel_time_mad_dp * 1000. / (double)(1000 * 1000 * 1000) : 0.0,
        kernel_time_mad_dp > 0.0 ? ((double)memoryoperations * sizeof(double)) / kernel_time_mad_dp * 1000. / (1000. * 1000. * 1000.) : 0.0,
        ((double)2 * computations) / ((double)memoryoperations * sizeof(__half2)),
        kernel_time_mad_hp,
        kernel_time_mad_hp > 0.0 ? ((double)2 * computations) / kernel_time_mad_hp * 1000. / (double)(1000 * 1000 * 1000) : 0.0,
        kernel_time_mad_hp > 0.0 ? ((double)memoryoperations * sizeof(__half2)) / kernel_time_mad_hp * 1000. / (1000. * 1000. * 1000.) : 0.0,
        ((double)computations) / ((double)memoryoperations * sizeof(int)),
        kernel_time_mad_int,
        ((double)computations) / kernel_time_mad_int * 1000. / (double)(1000 * 1000 * 1000),
        ((double)memoryoperations * sizeof(int)) / kernel_time_mad_int * 1000. / (1000. * 1000. * 1000.));
  }

  printf("------------------------------------------------------------------------------------------------------------------------------------------------------------------------\n");

  CUDA_SAFE_CALL(cudaMemcpy(c, d_buffer, size * sizeof(double), cudaMemcpyDeviceToHost));
  CUDA_SAFE_CALL(cudaFree(d_buffer));
}
